mapper.select:
select
change_type as changeType,
change_time as changeTime,
change_before as changeBefore,
change_after as changeAfter,
user_account as userAccount,
account_type as accountType,
user_label as userLabel,
control_rank as controlRank,
account_status as accountStatus,
operator as operator
from vip_change_info
where 1 = 1

    AND change_type = #{vo.changeType}


    AND user_account = #{vo.userAccount}


    AND operator = #{vo.operator}


    AND change_time  >=  #{vo.changeTimeStart}


    AND change_time  <=  #{vo.changeTimeEnd}


    order by ${vo.orderField} ${vo.orderType}


    order by change_time desc
